namespace sv_358aa7d9161041c18287e67aae220933.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button type="button" class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
    }
</div>

@code {
    [Parameter] public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = { "👍", "❤️", "😂", "🎉", "👀", "🔥" };

    private async Task SelectEmoji(string emoji)
    {
        await OnEmojiSelected.InvokeAsync(emoji);
    }
}

.emoji-picker {
    display: flex;
    gap: 4px;
    padding: 6px 8px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    position: absolute;
    bottom: 100%;
    left: 0;
    z-index: 100;
    margin-bottom: 4px;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.25rem;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
@using sv_358aa7d9161041c18287e67aae220933.Services

<div class="message-item">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button type="button"
                        class="btn btn-sm btn-outline-secondary reaction-badge"
                        @onclick="() => HandleReact(reaction.Emoji)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadInfo is not null)
    {
        <div class="thread-link">
            <a href="javascript:void(0)" @onclick="() => OnOpenThread.InvokeAsync(Message)">
                @ThreadInfo.ReplyCount replies &middot; last reply @FormatRelativeTime(ThreadInfo.LastReplyAt)
            </a>
        </div>
    }

    <div class="message-actions">
        <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="() => OnOpenThread.InvokeAsync(Message)">
            Reply
        </button>
        <div class="react-wrapper">
            <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="ToggleEmojiPicker">
                React
            </button>
            @if (showEmojiPicker)
            {
                <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public ThreadSummary? ThreadInfo { get; set; }

    private bool showEmojiPicker;

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await HandleReact(emoji);
    }

    private async Task HandleReact(string emoji)
    {
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 2) return "1 min ago";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 2) return "1 hour ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        if (diff.TotalDays < 2) return "yesterday";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-item:hover {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
}

.timestamp {
    font-size: 0.75rem;
    color: #868e96;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.5;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    font-size: 0.8rem;
    padding: 2px 8px;
    border-radius: 12px;
}

.thread-link {
    margin-top: 4px;
    font-size: 0.85rem;
}

.thread-link a {
    color: #0d6efd;
    text-decoration: none;
}

.thread-link a:hover {
    text-decoration: underline;
}

.message-actions {
    display: none;
    position: absolute;
    top: 4px;
    right: 8px;
    gap: 4px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.message-item:hover .message-actions {
    display: flex;
}

.react-wrapper {
    position: relative;
}

@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
@using sv_358aa7d9161041c18287e67aae220933.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @if (Channels is not null)
        {
            @foreach (var channel in Channels)
            {
                <div class="channel-item @(channel == ActiveChannel ? "active" : "")"
                     @onclick="() => OnChannelSelected.InvokeAsync(channel)">
                    <div class="channel-name">
                        <span class="hash">#</span> @channel.Name
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="badge bg-danger ms-auto">@channel.UnreadCount</span>
                        }
                    </div>
                    @if (!string.IsNullOrEmpty(channel.Description))
                    {
                        <div class="channel-desc">@Truncate(channel.Description, 50)</div>
                    }
                </div>
            }
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel>? Channels { get; set; }
    [Parameter] public Channel? ActiveChannel { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1e1e2e;
    color: #cdd6f4;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #313244;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #313244;
}

.sidebar-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
    font-weight: 700;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 2px 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #313244;
}

.channel-item.active {
    background: #45475a;
    color: #fff;
}

.channel-name {
    display: flex;
    align-items: center;
    font-size: 0.9rem;
    font-weight: 600;
}

.hash {
    margin-right: 4px;
    color: #6c7086;
}

.channel-desc {
    font-size: 0.75rem;
    color: #6c7086;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
@using sv_358aa7d9161041c18287e67aae220933.Services

<div class="message-area">
    @if (Channel is null)
    {
        <div class="placeholder-message">
            <h4>Select a channel to start chatting</h4>
        </div>
    }
    else
    {
        <div class="area-header">
            <h5># @Channel.Name</h5>
            <span class="header-desc">@Channel.Description</span>
        </div>

        <div class="message-list">
            <div class="load-more-container">
