@@ -1,0 +1,83 @@
+@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
+@using sv_358aa7d9161041c18287e67aae220933.Services
+
+<div class="message-item">
+    <div class="message-header">
+        <span class="author">@Message.Author</span>
+        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
+    </div>
+    <div class="message-content">@Message.Content</div>
+
+    @if (Message.Reactions.Count > 0)
+    {
+        <div class="reactions">
+            @foreach (var reaction in Message.Reactions)
+            {
+                <button type="button"
+                        class="btn btn-sm btn-outline-secondary reaction-badge"
+                        @onclick="() => HandleReact(reaction.Emoji)">
+                    @reaction.Emoji @reaction.Users.Count
+                </button>
+            }
+        </div>
+    }
+
+    @if (ThreadInfo is not null)
+    {
+        <div class="thread-link">
+            <a href="javascript:void(0)" @onclick="() => OnOpenThread.InvokeAsync(Message)">
+                @ThreadInfo.ReplyCount replies &middot; last reply @FormatRelativeTime(ThreadInfo.LastReplyAt)
+            </a>
+        </div>
+    }
+
+    <div class="message-actions">
+        <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="() => OnOpenThread.InvokeAsync(Message)">
+            Reply
+        </button>
+        <div class="react-wrapper">
+            <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="ToggleEmojiPicker">
+                React
+            </button>
+            @if (showEmojiPicker)
+            {
+                <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
+            }
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
+    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
+    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
+    [Parameter] public ThreadSummary? ThreadInfo { get; set; }
+
+    private bool showEmojiPicker;
+
+    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;
+
+    private async Task HandleEmojiSelected(string emoji)
+    {
+        showEmojiPicker = false;
+        await HandleReact(emoji);
+    }
+
+    private async Task HandleReact(string emoji)
+    {
+        await OnReact.InvokeAsync((Message.Id, emoji));
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt;
+        if (diff.TotalSeconds < 60) return "just now";
+        if (diff.TotalMinutes < 2) return "1 min ago";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
+        if (diff.TotalHours < 2) return "1 hour ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
+        if (diff.TotalDays < 2) return "yesterday";
+        return sentAt.ToString("MMM d, yyyy");
+    }
+}
+

