+@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
+@using sv_358aa7d9161041c18287e67aae220933.Services
+
+<div class="channel-sidebar">
+    <div class="sidebar-header">
+        <h5>Channels</h5>
+    </div>
+    <div class="channel-list">
+        @if (Channels is not null)
+        {
+            @foreach (var channel in Channels)
+            {
+                <div class="channel-item @(channel == ActiveChannel ? "active" : "")"
+                     @onclick="() => OnChannelSelected.InvokeAsync(channel)">
+                    <div class="channel-name">
+                        <span class="hash">#</span> @channel.Name
+                        @if (channel.UnreadCount > 0)
+                        {
+                            <span class="badge bg-danger ms-auto">@channel.UnreadCount</span>
+                        }
+                    </div>
+                    @if (!string.IsNullOrEmpty(channel.Description))
+                    {
+                        <div class="channel-desc">@Truncate(channel.Description, 50)</div>
+                    }
+                </div>
+            }
+        }
+    </div>
+</div>
+
+@code {
+    [Parameter] public List<Channel>? Channels { get; set; }
+    [Parameter] public Channel? ActiveChannel { get; set; }
+    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
+
+    private static string Truncate(string text, int maxLength) =>
+        text.Length <= maxLength ? text : text[..maxLength] + "…";
+}
+

