+@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
+@using sv_358aa7d9161041c18287e67aae220933.Services
+
+<div class="message-area">
+    @if (Channel is null)
+    {
+        <div class="placeholder-message">
+            <h4>Select a channel to start chatting</h4>
+        </div>
+    }
+    else
+    {
+        <div class="area-header">
+            <h5># @Channel.Name</h5>
+            <span class="header-desc">@Channel.Description</span>
+        </div>
+
+        <div class="message-list">
+            <div class="load-more-container">
+                @if (IsLoadingMore)
+                {
+                    <div class="spinner-border spinner-border-sm text-secondary" role="status">
+                        <span class="visually-hidden">Loading...</span>
+                    </div>
+                }
+                else
+                {
+                    <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="OnLoadMore">
+                        Load older messages
+                    </button>
+                }
+            </div>
+
+            @if (Messages is not null)
+            {
+                @foreach (var msg in Messages)
+                {
+                    <MessageItem Message="msg"
+                                 OnOpenThread="OnOpenThread"
+                                 OnReact="OnReact"
+                                 ThreadInfo="GetThreadSummary?.Invoke(msg.Id)" />
+                }
+            }
+        </div>
+
+        <div class="input-area">
+            <textarea class="form-control" rows="2" placeholder="Type a message..."
+                      @bind="newMessage" @bind:event="oninput"
+                      @onkeydown="HandleKeyDown"></textarea>
+            <button type="button" class="btn btn-primary" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(newMessage)">
+                Send
+            </button>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public Channel? Channel { get; set; }
+    [Parameter] public List<Message>? Messages { get; set; }
+    [Parameter] public bool IsLoadingMore { get; set; }
+    [Parameter] public EventCallback OnLoadMore { get; set; }
+    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
+    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
+    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
+    [Parameter] public Func<int, ThreadSummary?>? GetThreadSummary { get; set; }
+
+    private string newMessage = string.Empty;
+
+    private async Task SendMessage()
+    {
+        if (string.IsNullOrWhiteSpace(newMessage)) return;
+        var content = newMessage;
+        newMessage = string.Empty;
+        await OnSendMessage.InvokeAsync(content);
+    }
+
+    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await SendMessage();
+        }
+    }
+}
+

