+@namespace sv_358aa7d9161041c18287e67aae220933.Components.Chat
+@using sv_358aa7d9161041c18287e67aae220933.Services
+
+<div class="thread-panel">
+    <div class="thread-header">
+        <h6>Thread</h6>
+        <button type="button" class="btn-close" aria-label="Close" @onclick="OnClose"></button>
+    </div>
+
+    <div class="thread-body">
+        <div class="root-message card mb-3">
+            <div class="card-body">
+                <strong>@RootMessage.Author</strong>
+                <span class="text-muted small ms-2">@FormatRelativeTime(RootMessage.SentAt)</span>
+                <p class="card-text mt-1 mb-0">@RootMessage.Content</p>
+            </div>
+        </div>
+
+        <div class="thread-replies">
+            @if (Replies is not null)
+            {
+                @foreach (var reply in Replies)
+                {
+                    <div class="reply-item">
+                        <div class="reply-header">
+                            <strong>@reply.Author</strong>
+                            <span class="text-muted small ms-2">@FormatRelativeTime(reply.SentAt)</span>
+                        </div>
+                        <div class="reply-content">@reply.Content</div>
+                    </div>
+                }
+            }
+        </div>
+    </div>
+
+    <div class="thread-input">
+        <textarea class="form-control" rows="2" placeholder="Reply..."
+                  @bind="replyText" @bind:event="oninput"
+                  @onkeydown="HandleKeyDown"></textarea>
+        <button type="button" class="btn btn-primary mt-2" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(replyText)">
+            Reply
+        </button>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
+    [Parameter] public List<Message>? Replies { get; set; }
+    [Parameter] public EventCallback OnClose { get; set; }
+    [Parameter] public EventCallback<string> OnSendReply { get; set; }
+
+    private string replyText = string.Empty;
+
+    private async Task SendReply()
+    {
+        if (string.IsNullOrWhiteSpace(replyText)) return;
+        var content = replyText;
+        replyText = string.Empty;
+        await OnSendReply.InvokeAsync(content);
+    }
+
+    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter" && !e.ShiftKey)
+        {
+            await SendReply();
+        }
+    }
+
+    private static string FormatRelativeTime(DateTime sentAt)
+    {
+        var diff = DateTime.UtcNow - sentAt;
+        if (diff.TotalSeconds < 60) return "just now";
+        if (diff.TotalMinutes < 2) return "1 min ago";
+        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
+        if (diff.TotalHours < 2) return "1 hour ago";
+        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
+        if (diff.TotalDays < 2) return "yesterday";
+        return sentAt.ToString("MMM d, yyyy");
+    }
+}
+

