 @page "/chat"
 @layout ChatLayout
 @rendermode InteractiveServer
 @using sv_358aa7d9161041c18287e67aae220933.Services
 @using sv_358aa7d9161041c18287e67aae220933.Components.Chat
 @inject IChatService ChatService

 <div class="chat-layout">
     <ChannelSidebar Channels="channels"
                     ActiveChannel="selectedChannel"
                     OnChannelSelected="SelectChannelAsync" />

     <MessageArea Channel="selectedChannel"
                  Messages="messages"
                  IsLoadingMore="isLoadingMore"
                  OnLoadMore="LoadMoreMessagesAsync"
                  OnSendMessage="SendMessageAsync"
                  OnOpenThread="OpenThreadAsync"
                  OnReact="AddReactionAsync"
                  GetThreadSummary="GetThreadSummary" />

     @if (activeThread is not null)
     {
         <ThreadPanel RootMessage="activeThread"
                      Replies="threadMessages"
                      OnClose="CloseThread"
                      OnSendReply="SendThreadReplyAsync" />
     }
 </div>

 @code {
     private List<Channel> channels = new();
     private Channel? selectedChannel;
     private List<Message> messages = new();
     private Message? activeThread;
     private List<Message> threadMessages = new();
     private bool isLoadingMore;
     private int messageSkip;
     private const int PageSize = 50;

     protected override async Task OnInitializedAsync()
     {
         channels = await ChatService.GetChannelsAsync();
     }

     private async Task SelectChannelAsync(Channel channel)
     {
         selectedChannel = channel;
         messageSkip = 0;
         messages = new();
         activeThread = null;
         threadMessages = new();

         messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
         messageSkip = messages.Count;

         await ChatService.MarkChannelReadAsync(channel.Id);

         var idx = channels.FindIndex(c => c.Id == channel.Id);
         if (idx >= 0)
         {
             channels[idx] = channel with { UnreadCount = 0 };
         }
     }

     private async Task LoadMoreMessagesAsync()
     {
         if (selectedChannel is null || isLoadingMore) return;

         isLoadingMore = true;
         try
         {
             var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messageSkip, PageSize);
             messages.InsertRange(0, older);
             messageSkip += older.Count;
         }
         finally
         {
             isLoadingMore = false;
         }
     }

     private async Task SendMessageAsync(string content)
     {
         if (selectedChannel is null) return;
         var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
         messages.Add(msg);
     }

     private async Task OpenThreadAsync(Message rootMessage)
     {
         activeThread = rootMessage;
         threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
     }

     private void CloseThread()
     {
         activeThread = null;
         threadMessages = new();
     }

     private async Task SendThreadReplyAsync(string content)
     {
         if (activeThread is null || selectedChannel is null) return;
         var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, activeThread.Id);
         threadMessages.Add(reply);
         messages.Add(reply);
     }

     private async Task AddReactionAsync((int MessageId, string Emoji) args)
     {
         await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

         UpdateReactionInList(messages, args.MessageId, args.Emoji);
         UpdateReactionInList(threadMessages, args.MessageId, args.Emoji);
     }

     private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
     {
         var idx = list.FindIndex(m => m.Id == messageId);
         if (idx < 0) return;

         var msg = list[idx];
         var reactions = msg.Reactions.ToList();
         var existing = reactions.FindIndex(r => r.Emoji == emoji);
         if (existing >= 0)
         {
             var r = reactions[existing];
             reactions[existing] = r with { Users = new List<string>(r.Users) { "You" } };
         }
         else
         {
             reactions.Add(new Reaction(emoji, new List<string> { "You" }));
         }
         list[idx] = msg with { Reactions = reactions };
     }

     private ThreadSummary? GetThreadSummary(int messageId)
     {
         var replies = messages.Where(m => m.ReplyToId == messageId).ToList();
         if (replies.Count == 0) return null;
         return new ThreadSummary(messageId, replies.Count, replies.Max(r => r.SentAt));
     }
 }

